#!/bin/bash

# 修改为实际的 JAR 文件名（不含路径）
APP_NAME=app.jar
# 修改为 JAR 文件所在目录
APP_PATH=/opt/app/jar

usage() {
    echo "Usage: sh server.sh [start|stop|restart|status]"
    exit 1
}

is_exist() {
    pid=$(ps -ef | grep $APP_NAME | grep -v grep | awk '{print $2}')
    if [ -z "${pid}" ]; then
        return 1
    else
        return 0
    fi
}

start_log() {
    is_exist
    if [ $? -eq 0 ]; then
        echo "${APP_NAME} 启动成功！pid=${pid}"
    else
        echo "${APP_NAME} 启动失败，请检查后重试"
    fi
}

start() {
    is_exist
    if [ $? -eq 0 ]; then
        echo "${APP_NAME} is already running. pid=${pid}"
    else
        nohup java -jar ${APP_PATH}/${APP_NAME} > /dev/null 2>&1 &
        start_log
    fi
}

stop() {
    is_exist
    if [ $? -eq 0 ]; then
        kill -9 $pid
        echo "${APP_NAME} 已关闭！pid=${pid}"
    else
        echo "${APP_NAME} is not running"
    fi
}

status() {
    is_exist
    if [ $? -eq 0 ]; then
        echo "${APP_NAME} is running. Pid is ${pid}"
    else
        echo "${APP_NAME} is not running."
    fi
}

restart() {
    stop
    echo "${APP_NAME} 准备重启..."
    sleep 5
    start
}

case "$1" in
    "start")   start   ;;
    "stop")    stop    ;;
    "status")  status  ;;
    "restart") restart ;;
    *)         usage   ;;
esac
